#include <omp.h>

void parallel_matrix_add(float* A, float* B, float* C, int N) {
 #pragma omp parallel for schedule(static)
 for (int i = 0; i < N; i++) {
 for (int j = 0; j < N; j++) {
 C[i][j] = A[i][j] + B[i][j];
 }
 }
}

