// Each thread executes same loop body
// Operating on different data elements (rows)
// Implicit synchronization at end of parallel region

#include <mpi.h>

void mpi_computation(double* local_data, int local_size, int rank, int size) {
 // Each process has its own local_data (distributed memory)

 // Compute local result
 double local_result = compute(local_data, local_size);

 // Send to rank 0 if not root
 if (rank != 0) {
 MPI_Send(&local_result, 1, MPI_DOUBLE, 0, 0, MPI_COMM_WORLD);
 } else {
 // Root receives and reduces
 double total = local_result;
 double received;
 for (int src = 1; src < size; src++) {
 MPI_Recv(&received, 1, MPI_DOUBLE, src, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 total += received;
 }
 printf("Total: %f\n", total);
 }
}

// This follows SPMD model: same program runs on all ranks
// Each rank has different data and may take different paths

void task_parallel_pipeline(DataStream& input, DataStream& output) {
 #pragma omp parallel sections num_threads(3)
 {
 #pragma omp section
 {
 // Stage 1: Read and preprocess
 while (more_data) {
 DataChunk chunk = input.read();
 preprocess(chunk);
 stage1_buffer.push(chunk);
 }
 }

 #pragma omp section
 {
 // Stage 2: Process data
 while (more_data) {
 DataChunk chunk = stage1_buffer.pop();
 process(chunk);
 stage2_buffer.push(chunk);
 }
 }

 #pragma omp section
 {
 // Stage 3: Write results
 while (more_data) {
 DataChunk chunk = stage2_buffer.pop();
 output.write(chunk);
 }
 }
 }
}

// Each section runs in parallel - different tasks simultaneously
// Pipeline parallelism: stages process different data concurrently
